import multiprocessing as mp

def worker(in_q, out_q):
    for n in iter(in_q.get, None):   # stop when we receive the sentinel None
        out_q.put((n, n * n))

if __name__ == "__main__":
    in_q, out_q = mp.Queue(), mp.Queue()
    procs = [mp.Process(target=worker, args=(in_q, out_q)) for _ in range(3)]
    for p in procs:
        p.start()

    for n in range(10):
        in_q.put(n)
    for _ in procs:
        in_q.put(None)              # one sentinel per worker

    results = [out_q.get() for _ in range(10)]
    for p in procs:
        p.join()
    print(sorted(results))

