import time

def heavy(n):
    return sum(i * i for i in range(n))

if __name__ == "__main__":
    work = [5_000_000] * 8
    start = time.perf_counter()
    results = [heavy(n) for n in work]
    print("serial:", round(time.perf_counter() - start, 2), "s")

